              <CardContent className="p-0">
                <Table>
                  <TableHeader className="bg-muted/30">
                    <TableRow className="hover:bg-transparent border-b border-border h-14">
                      <TableHead className="pl-10 font-black uppercase tracking-widest text-[10px]">
