'use client';

import { useEffect, useState, Suspense } from 'react';
import Link from 'next/link';
import { motion } from 'framer-motion';
import {
  ArrowLeft,
  ArrowRight,
  BookOpen,
  Clock,
  RefreshCw,
  Mail,
  Sparkles,
  ChevronLeft,
  ChevronRight,
} from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { supabase } from '@/lib/supabase';
import { blogPosts as staticBlogs } from '@/lib/blog-data';

const POSTS_PER_PAGE = 10;

export default function BlogListPage() {
  const [blogs, setBlogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalCount, setTotalCount] = useState(0);

  useEffect(() => {
    async function fetchBlogs() {
      setLoading(true);
      try {
        const from = (currentPage - 1) * POSTS_PER_PAGE;
        const to = from + POSTS_PER_PAGE - 1;

        const { data, error, count } = await supabase
          .from('blogs')
          .select('*', { count: 'exact' })
          .order('created_at', { ascending: false })
          .range(from, to);

        if (error) throw error;

        if (data && data.length > 0) {
          setBlogs(data);
          setTotalCount(count || data.length);
        } else {
          // Fallback to static blogs for demo/initial state
          setBlogs(staticBlogs.slice(from, from + POSTS_PER_PAGE));
          setTotalCount(staticBlogs.length);
        }
      } catch (err) {
        console.error('Error fetching blogs:', err);
        setBlogs(staticBlogs.slice(0, POSTS_PER_PAGE));
        setTotalCount(staticBlogs.length);
      } finally {
        setLoading(false);
      }
    }

    fetchBlogs();
  }, [currentPage]);

  const totalPages = Math.ceil(totalCount / POSTS_PER_PAGE);

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <main className="flex-1 pb-24">
