export function AIAssistant() {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedModel, setSelectedModel] = useState(MODELS[0].id);
  const [attachedFile, setAttachedFile] = useState(null);
  const [filePreview, setFilePreview] = useState(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [openRouterKey, setOpenRouterKey] = useState('');
  const [sessions, setSessions] = useState([]);
  const [currentSessionId, setCurrentSessionId] = useState(null);

  const scrollRef = useRef(null);
  const fileInputRef = useRef(null);

  // Load saved data on mount
  useEffect(() => {
    const savedKey = localStorage.getItem('openrouter_key') || '';
    setOpenRouterKey(savedKey);

    const savedSessions = localStorage.getItem('ai_sessions');
    const savedCurrentId = localStorage.getItem('ai_current_session_id');

    if (savedSessions) {
      try {
        const parsed = JSON.parse(savedSessions);
        setSessions(parsed);
        if (savedCurrentId && parsed.find((s) => s.id === savedCurrentId)) {
          const session = parsed.find((s) => s.id === savedCurrentId);
          setCurrentSessionId(savedCurrentId);
          setMessages(session.messages || []);
          setSelectedModel(session.model || MODELS[0].id);
        } else if (parsed.length > 0) {
          setCurrentSessionId(parsed[0].id);
          setMessages(parsed[0].messages || []);
          setSelectedModel(parsed[0].model || MODELS[0].id);
        } else {
          createNewSession();
        }
      } catch (e) {
        console.error('Failed to load sessions:', e);
        createNewSession();
      }
    } else {
      createNewSession();
    }
  }, []);

  // Persistence to localStorage
  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('ai_sessions', JSON.stringify(sessions));
    }
    if (currentSessionId) {
      localStorage.setItem('ai_current_session_id', currentSessionId);
    }
  }, [sessions, currentSessionId]);

  // Sync current session state with the sessions list
  useEffect(() => {
    if (!currentSessionId) return;

    setSessions((prev) =>
      prev.map((s) => {
        if (s.id === currentSessionId) {
          let newTitle = s.title;
          if ((s.title === 'New Chat' || !s.title) && messages.length > 0) {
            const firstUserMsg = messages.find((m) => m.role === 'user');
            if (firstUserMsg) {
              newTitle =
                firstUserMsg.content.slice(0, 40) +
                (firstUserMsg.content.length > 40 ? '...' : '');
            }
          }
          return {
            ...s,
            messages: messages.filter((m) => !m.tempId),
            model: selectedModel,
            title: newTitle,
            updatedAt: Date.now(),
          };
        }
        return s;
      })
    );
  }, [messages, selectedModel, currentSessionId]);

  const createNewSession = () => {
    const newSession = {
      id: Date.now().toString(),
      title: 'New Chat',
      messages: [],
      model: MODELS[0].id,
      createdAt: Date.now(),
      updatedAt: Date.now(),
    };
    setSessions((prev) => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setMessages([]);
    setSelectedModel(MODELS[0].id);
  };

  const switchSession = (id) => {
    const s = sessions.find((sess) => sess.id === id);
    if (s) {
      setCurrentSessionId(id);
      setMessages(s.messages || []);
      setSelectedModel(s.model || MODELS[0].id);
    }
  };

  const deleteSession = (id, e) => {
    if (e) e.stopPropagation();
    const updated = sessions.filter((s) => s.id !== id);
    setSessions(updated);
    if (currentSessionId === id) {
      if (updated.length > 0) {
        switchSession(updated[0].id);
      } else {
        createNewSession();
      }
    }
  };

  const clearAllChats = () => {
    setSessions([]);
    createNewSession();
    localStorage.removeItem('ai_sessions');
    localStorage.removeItem('ai_current_session_id');
  };

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const saveKey = () => {
    localStorage.setItem('openrouter_key', openRouterKey);
    toast.success('Intelligence Sequence Synchronized');
  };

  const handleFileSelect = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setAttachedFile(file);
    if (file.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onload = (e) => setFilePreview(e.target.result);
      reader.readAsDataURL(file);
    } else {
      setFilePreview('file');
    }
  };

  const removeAttachment = () => {
    setAttachedFile(null);
    setFilePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const fileToBase64 = (file) =>
    new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result.split(',')[1]);
      reader.onerror = (error) => reject(error);
    });

  const handleSend = async () => {
    if ((!input.trim() && !attachedFile) || isLoading) return;

    const currentInput = input;
    const currentFile = attachedFile;
    const currentPreview = filePreview;

    const userMessage = {
      role: 'user',
      content: currentInput,
      timestamp: new Date(),
      attachment:
        currentPreview && currentFile?.type.startsWith('image/')
          ? currentPreview
          : null,
      fileName: currentFile?.name,
    };

    setMessages((prev) => [...prev, userMessage]);
    setInput('');
    removeAttachment();
    setIsLoading(true);

    // IMAGE GENERATION (Instant via Pollinations)
    if (selectedModel === 'image-gen') {
      try {
        const enhancedPrompt = `${currentInput}, cinematic lighting, high resolution, 8k, highly detailed, professional masterpiece`;
        const seed = Math.floor(Math.random() * 1000000);
        const imageUrl = `https://image.pollinations.ai/prompt/${encodeURIComponent(enhancedPrompt)}?width=1024&height=1024&nologo=true&private=true&enhance=true&seed=${seed}`;

        // Create a temporary loading message
        const loadingMsgIndex = messages.length;
        setMessages((prev) => [
          ...prev,
          {
            role: 'assistant',
            content: `🎨 Generating neural art for: "${currentInput}"...`,
            timestamp: new Date(),
            tempId: `loading-${Date.now()}`,
          },
        ]);

        // Preload the image to ensure it's ready before displaying
        const img = new Image();

        await new Promise((resolve, reject) => {
          const timeout = setTimeout(() => {
            reject(
              new Error(
                'Image generation timed out. The service might be busy.'
              )
            );
          }, 30000); // 30 seconds timeout

          img.onload = () => {
            clearTimeout(timeout);
            resolve();
          };

          img.onerror = () => {
            clearTimeout(timeout);
            reject(new Error('Failed to load generated image'));
          };

          img.src = imageUrl;
        });

        // Remove loading message and add the actual image
        setMessages((prev) =>
          prev
            .filter((m) => !m.tempId)
            .concat({
              role: 'assistant',
              content: `Generated neural art for: "${currentInput}"`,
              type: 'image',
              url: imageUrl,
              timestamp: new Date(),
            })
        );
      } catch (error) {
        console.error('[Image Gen Error]:', error);
        setMessages((prev) =>
          prev
            .filter((m) => !m.tempId)
            .concat({
              role: 'assistant',
              content: `⚠️ Image generation failed: ${error.message}. This can happen when:
- The service is experiencing high load
- Your prompt contains restricted content
- Network connectivity issues

**Tip:** Try simplifying your prompt or wait a moment before trying again.`,
              timestamp: new Date(),
            })
        );
      } finally {
        setIsLoading(false);
      }
      return;
    }

    // TEXT & CODE GENERATION
    try {
      const systemPrompt =
        selectedModel === 'coder'
          ? 'You are a professional software engineer. Provide high-quality, efficient code. ' +
            PROJECT_KNOWLEDGE
          : 'You are a helpful assistant for HAZWOPER Useful Tools. ' +
            PROJECT_KNOWLEDGE;

      const chatMessages = [
        { role: 'system', content: systemPrompt },
        ...messages
          .filter((m) => !m.type)
          .map((m) => ({ role: m.role, content: m.content })),
        { role: 'user', content: currentInput },
      ];

      // Try OpenRouter if Key is provided, else use Free Neural Cluster
      if (openRouterKey) {
        const routerModel =
          selectedModel === 'coder'
            ? 'deepseek/deepseek-coder-33b-instruct'
            : 'meta-llama/llama-3.1-405b-instruct';
        try {
          const orResponse = await fetch(
            'https://openrouter.ai/api/v1/chat/completions',
            {
              method: 'POST',
              headers: {
                Authorization: `Bearer ${openRouterKey}`,
                'HTTP-Referer': window.location.origin,
                'X-Title': 'HAZWOPER AI',
                'Content-Type': 'application/json',
              },
              body: JSON.stringify({
                model: routerModel,
                messages: chatMessages,
              }),
            }
          );
          const orData = await orResponse.json();
          if (orData.choices?.[0]?.message) {
            setMessages((prev) => [
              ...prev,
              {
                role: 'assistant',
                content: orData.choices[0].message.content,
                timestamp: new Date(),
                model: 'Llama 3.1',
              },
            ]);
            setIsLoading(false);
            return;
          }
        } catch (e) {
          console.warn('OpenRouter failed, falling back to free cluster.');
        }
      }

      // Free Neural Cluster (Pollinations - 100% Working)
      const pollinationsModel =
        selectedModel === 'coder' ? 'searchgpt' : 'openai';
      const pollinationsUrl = `https://text.pollinations.ai/`;

      const response = await fetch(pollinationsUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          messages: chatMessages,
          model: pollinationsModel,
          seed: Math.floor(Math.random() * 1000000),
          json: false,
        }),
      });

      if (!response.ok) {
        // Fallback to GET request if POST fails
        const lastMsg = currentInput;
        const fallbackUrl = `https://text.pollinations.ai/${encodeURIComponent(lastMsg)}?model=${pollinationsModel}&system=${encodeURIComponent(systemPrompt)}`;
        const fallbackResponse = await fetch(fallbackUrl);
        if (!fallbackResponse.ok) throw new Error('Neural cluster unavailable');
        const fallbackText = await fallbackResponse.text();

        setMessages((prev) => [
          ...prev,
          {
            role: 'assistant',
            content: fallbackText.trim(),
            timestamp: new Date(),
            model: selectedModel === 'coder' ? 'DeepSeek' : 'Neural 3.5',
          },
        ]);
        return;
      }

      const responseText = await response.text();

      // Clean up Pollinations specific branding or notices if they appear
      const cleanText = responseText
        .replace(/IMPORTANT NOTICE:[\s\S]*?\n\n/g, '')
        .replace(/Pollinations\.ai/gi, 'Neural Intelligence')
        .trim();

      setMessages((prev) => [
        ...prev,
        {
          role: 'assistant',
          content:
            cleanText ||
            'Neural cluster is processing. Please try again in a moment.',
          timestamp: new Date(),
          model: selectedModel === 'coder' ? 'DeepSeek' : 'Neural 3.5',
        },
      ]);
    } catch (error) {
      setMessages((prev) => [
        ...prev,
        {
          role: 'assistant',
