              )}

              {/* Textarea Content */}
              {(blogCode || faqCode) && (
                <div className="flex-1 p-4 flex flex-col h-full overflow-hidden">
                  <div className="flex items-center justify-between mb-2 mt-2">
                    <h4 className="text-sm font-semibold flex items-center gap-2">
                      <Code className="h-4 w-4" />
                      {activeView === 'content'
                        ? 'Blog HTML Code'
                        : 'FAQ HTML Code'}
