                    <div className="flex gap-2">
                      <Button
                        variant="outline"
                        size="sm"
                        className="preview-icon-btn"
                        onClick={() => {
                          const content =
                            activeView === 'content' ? blogCode : faqCode;
                          const title =
                            activeView === 'content' ? 'Blog Post' : 'FAQ';
                          openPreview(content, title);
