  AccordionItem,
  AccordionTrigger,
} from '@/components/ui/accordion';
import {
  Eraser,
  Eye,
  History,
  Undo2,
  Copy,
  Trash2,
  FileText,
  Code,
  Settings,
} from 'lucide-react';
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from '@/components/ui/sheet';
import { PreviewDrawer } from '@/components/preview-drawer';
import { cleanHTML, getHTMLStats, getReductionRate } from '@/lib/html-cleaner';
import { ProgressButton } from '@/components/progress-button';
import { saveGeneratorState } from '@/lib/tool-history';
import { HistoryList } from '@/components/history-list';

const defaultOptions = {
  removeNBSP: true,
  removeClasses: true,
  removeIds: true,
  removeStyleAttrs: true,
  removeDataAttrs: true,
  removeEmptyTags: true,
  removeInlineStyles: true,
  removeFontTags: false,
  minifyHTML: false,
  beautifyHTML: false,
  preserveEssentialAttrs: true,
  removeComments: true,
  normalizeWhitespace: true,
  removeScriptStyleTags: true,
  removeBrTags: true,
  convertLineBreaks: true,
};

const optionLabels = {
  removeNBSP: { label: 'Remove &nbsp;' },
  removeClasses: { label: 'Remove classes' },
  removeIds: { label: 'Remove IDs' },
  removeStyleAttrs: { label: 'Remove style attrs' },
  removeDataAttrs: { label: 'Remove data attrs' },
  removeEmptyTags: { label: 'Remove empty tags' },
  removeInlineStyles: { label: 'Remove inline styles' },
  removeFontTags: { label: 'Remove font/span' },
  minifyHTML: { label: 'Minify HTML' },
  beautifyHTML: { label: 'Beautify HTML' },
  preserveEssentialAttrs: { label: 'Preserve essential' },
  removeComments: { label: 'Remove comments' },
  normalizeWhitespace: { label: 'Normalize whitespace' },
  removeScriptStyleTags: { label: 'Remove script/style' },
  removeBrTags: { label: 'Remove <br> tags' },
  convertLineBreaks: { label: 'Convert line breaks' },
};

export function HTMLCleaner() {
  const { performAction } = useAuthAction();
  const [html, setHtml] = useState('');
  const [options, setOptions] = useState(defaultOptions);
  const [stats, setStats] = useState({
    charCount: 0,
    wordCount: 0,
    nbspCount: 0,
    tagCount: 0,
    cleanScore: 0,
  });
  const [reductionRate, setReductionRate] = useState(0);
  const [history, setHistory] = useState([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const [previewOpen, setPreviewOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  // Update stats when HTML changes
  useEffect(() => {
    if (typeof window !== 'undefined' && html) {
      const newStats = getHTMLStats(html);
      setStats(newStats);
    }
  }, [html]);


  const handleClean = useCallback(() => {
    if (!html.trim()) {
      toast.error('Please enter some HTML first');
      return;
    }

    setIsProcessing(true);

    // Save current state to local undo history
    setHistory((prev) => [...prev.slice(0, historyIndex + 1), html]);
    setHistoryIndex((prev) => prev + 1);

    try {
      const cleaned = cleanHTML(html, options);
      const reduction = getReductionRate(html, cleaned);

      setHtml(cleaned);
      setReductionRate(reduction);
      toast.success(`HTML cleaned! Reduced by ${reduction}%`);

      // Auto-save the cleaned state
      (async () => {
        await saveGeneratorState(
          'html_cleaner',
          {
            html: cleaned,
            options,
          },
          `Cleaned HTML - ${new Date().toLocaleTimeString()}`
        );
      })();
    } catch (error) {
      toast.error('Error cleaning HTML: ' + error.message);
    } finally {
      setIsProcessing(false);
    }
  }, [html, options, historyIndex]);

  const handleUndo = () => {
    if (historyIndex >= 0) {
      setHtml(history[historyIndex]);
      setHistoryIndex((prev) => prev - 1);
      toast.info('Undo successful');
    }
  };

  const handleCopy = async () => {
    if (!html.trim()) {
      toast.error('Nothing to copy');
      return;
    }
    performAction(
      async () => {
        await navigator.clipboard.writeText(html);
      },
      { type: 'copy', name: 'HTML Cleaner' }
    );
  };

  const handleClear = () => {
    if (html) {
      setHistory((prev) => [...prev, html]);
      setHistoryIndex((prev) => prev + 1);
    }
    setHtml('');
    setReductionRate(0);
    toast.info('Editor cleared');
  };

  const handleRestore = (state) => {
    if (!state) return;
    setHtml(state.html || '');
    if (state.options) setOptions(state.options);
    toast.success('HTML session synchronized');
  };

  const toggleOption = (key) => {
    setOptions((prev) => ({ ...prev, [key]: !prev[key] }));
  };

  const selectAll = () => {
    setOptions(
      Object.fromEntries(Object.keys(defaultOptions).map((k) => [k, true]))
    );
  };

  const deselectAll = () => {
    setOptions(
      Object.fromEntries(Object.keys(defaultOptions).map((k) => [k, false]))
    );
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-end">
        <Sheet>
          <SheetTrigger asChild>
            <Button
              variant="outline"
              className="h-11 rounded-xl font-black uppercase tracking-widest text-[10px] gap-2 border-primary/20 hover:bg-primary/5 transition-all shadow-sm"
            >
              <History className="h-4 w-4 text-primary" /> Neural Sync History
            </Button>
          </SheetTrigger>
          <SheetContent
            side="right"
            className="w-full sm:max-w-[50%] p-0 glass-panel-deep border-l border-border animate-in slide-in-from-right duration-500 z-[200]"
          >
            <SheetHeader className="p-8 border-b border-border/50 bg-muted/20">
              <SheetTitle className="flex items-center gap-3 text-sm font-black">
                <div className="h-10 w-10 rounded-xl bg-primary/10 flex items-center justify-center">
                  <History className="h-5 w-5 text-primary" />
                </div>
                Neural Sync Hub
              </SheetTitle>
            </SheetHeader>
            <HistoryList toolType="html_cleaner" onRestore={handleRestore} />
          </SheetContent>
        </Sheet>
      </div>

      <Card className="card">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Eraser className="h-5 w-5 text-blue-500" />
            Advanced HTML Cleaner
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex flex-wrap gap-2">
            <ProgressButton
              onClick={handleClean}
              disabled={isProcessing || !html.trim()}
              isLoading={isProcessing}
              label="Clean HTML"
              loadingLabel="Cleaning..."
              className="bg-primary hover:bg-primary/90 text-primary-foreground text-sm font-semibold px-6 h-10 rounded-xl shadow-sm transition-all"
              variant="default"
            />
            <Button
              variant="outline"
              onClick={() => setPreviewOpen(true)}
              className="h-10 rounded-xl"
            >
              <Eye className="mr-2 h-4 w-4" /> Preview
            </Button>
            <Button
              variant="outline"
              onClick={handleUndo}
              disabled={historyIndex < 0}
              className="h-10 rounded-xl"
            >
              <Undo2 className="mr-2 h-4 w-4" /> Undo
            </Button>
            <Button
              variant="outline"
              onClick={handleCopy}
              className="h-10 rounded-xl"
            >
              <Copy className="mr-2 h-4 w-4" /> Copy
            </Button>
            <Button
              variant="outline"
              onClick={handleClear}
              className="h-10 rounded-xl"
            >
              <Trash2 className="mr-2 h-4 w-4" /> Clear
            </Button>
          </div>

          <div className="space-y-2">
            <Label className="flex items-center gap-2">
              <Code className="h-4 w-4" /> Paste your HTML here:
            </Label>
            <Textarea
              value={html}
              onChange={(e) => setHtml(e.target.value)}
              placeholder="Paste your HTML content here..."
              className="min-h-[300px] font-mono text-sm rounded-xl bg-muted/30"
            />
          </div>

          <div className="grid grid-cols-3 md:grid-cols-6 gap-2">
            {[
              { label: 'Chars', value: stats.charCount.toLocaleString() },
              { label: 'Words', value: stats.wordCount.toLocaleString() },
              { label: 'nbsp', value: stats.nbspCount },
              { label: 'Tags', value: stats.tagCount },
              { label: 'Score', value: `${stats.cleanScore}%` },
              {
                label: 'Reduction',
                value: `${reductionRate}%`,
                color: 'text-green-500',
              },
            ].map((stat, i) => (
              <div
                key={i}
                className="rounded-xl border p-3 text-center bg-muted/20"
              >
                <div className="text-[10px] uppercase font-bold text-muted-foreground">
                  {stat.label}
                </div>
                <div className={`text-lg font-black ${stat.color || ''}`}>
                  {stat.value}
                </div>
              </div>
            ))}
          </div>

          <Accordion type="single" collapsible className="w-full">
            <AccordionItem value="options" className="border-none">
              <AccordionTrigger className="hover:no-underline py-2">
                <div className="flex items-center gap-2 text-sm font-bold">
                  <Settings className="h-4 w-4" /> Cleaning Options
                </div>
              </AccordionTrigger>
              <AccordionContent>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 pt-4">
                  {Object.entries(optionLabels).map(([key, { label }]) => (
                    <div key={key} className="flex items-center space-x-2">
                      <Switch
                        id={key}
                        checked={options[key]}
                        onCheckedChange={() => toggleOption(key)}
                      />
                      <Label htmlFor={key} className="text-xs cursor-pointer">
                        {label}
                      </Label>
                    </div>
                  ))}
                </div>
                <div className="flex gap-2 mt-6 pt-4 border-t border-border/50">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={selectAll}
                    className="rounded-lg text-[10px] h-8 px-4 font-black uppercase"
                  >
                    Select All
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={deselectAll}
                    className="rounded-lg text-[10px] h-8 px-4 font-black uppercase"
                  >
                    Deselect All
                  </Button>
                </div>
              </AccordionContent>
            </AccordionItem>
          </Accordion>
        </CardContent>
      </Card>

      <PreviewDrawer
        open={previewOpen}
        onOpenChange={setPreviewOpen}
        title="HTML Preview"
        content={html}
      />
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Upload,
  FileImage,
  Copy,
  Download,
  Loader2,
  CheckCircle2,
  AlertCircle,
  Sparkles,
  Zap,
  Clipboard,
} from 'lucide-react';
import Tesseract from 'tesseract.js';
import { ProgressButton } from '@/components/progress-button';
import { cn } from '@/lib/utils';
import { useAuthAction } from '@/lib/use-auth-action';
import { toast } from 'sonner';
import { saveGeneratorState } from '@/lib/tool-history';

export default function ImageToText() {
  const { performAction } = useAuthAction();
  const [selectedFile, setSelectedFile] = useState(null);
  const [previewUrl, setPreviewUrl] = useState(null);
  const [extractedText, setExtractedText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState('');
  const [useAI, setUseAI] = useState(true); // Default to AI mode - using 100% FREE APIs (no quota limits!)
  const [copied, setCopied] = useState(false);

  // Auto-save helper
  const persistState = async (updates = {}) => {
    const currentState = {
      extractedText,
      fileName: selectedFile?.name || 'OCR Session',
      ...updates,
    };
    await saveGeneratorState('image_to_text', currentState);
  };

  const handleFileSelect = useCallback((e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const validTypes = [
      'image/jpeg',
      'image/jpg',
      'image/png',
      'image/gif',
      'image/bmp',
      'image/webp',
      'image/tiff',
    ];
    if (!validTypes.includes(file.type)) {
      setError(
        'Please upload a valid image file (JPG, PNG, GIF, BMP, WEBP, TIFF)'
      );
      return;
    }

    const maxSize = 10 * 1024 * 1024; // 10MB
    if (file.size > maxSize) {
      setError('File size must be less than 10MB');
      return;
    }

    setSelectedFile(file);
    setError('');
    setExtractedText('');
    setProgress(0);

    const reader = new FileReader();
    reader.onloadend = () => {
      setPreviewUrl(reader.result);
    };
    reader.readAsDataURL(file);
  }, []);

  // Preprocess image for better OCR accuracy
  const preprocessImage = (imageUrl, compress = false) => {
    return new Promise((resolve) => {
      const img = new Image();
      img.crossOrigin = 'anonymous';
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');

        // Scale up small images for better recognition
        let scale = Math.max(1, 2000 / Math.max(img.width, img.height));

        // If compressing for cloud APIs, cap the dimensions to keep file size low
        // Free OCR.space has a 1024KB limit. We stay well under.
        if (compress) {
          const maxDim = 1200; // Reduced from 1600 for safety
          if (Math.max(img.width, img.height) * scale > maxDim) {
            scale = maxDim / Math.max(img.width, img.height);
          }
        }

        canvas.width = img.width * scale;
        canvas.height = img.height * scale;

        // Draw original image scaled up
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height);

        // Get image data for processing
        const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
        const data = imageData.data;

        // Convert to grayscale and increase contrast
        for (let i = 0; i < data.length; i += 4) {
          // Grayscale
          const gray =
            0.299 * data[i] + 0.587 * data[i + 1] + 0.114 * data[i + 2];

          // Increase contrast (factor 1.4)
          const contrast = 1.4;
          const adjusted = (gray - 128) * contrast + 128;
          const final = Math.max(0, Math.min(255, adjusted));

          data[i] = final;
          data[i + 1] = final;
          data[i + 2] = final;
        }

        ctx.putImageData(imageData, 0, 0);

        // Use JPEG for compression, PNG for standard (lossless)
        const format = compress ? 'image/jpeg' : 'image/png';
        const quality = compress ? 0.75 : 1.0;
        resolve(canvas.toDataURL(format, quality));
      };
      img.src = imageUrl;
    });
  };

  const extractWithAI = async (base64Image) => {
    try {
      // Log size for debugging (AI Mode)
      const sizeInMB = (base64Image.length * (3 / 4)) / (1024 * 1024);
      console.log(
        `[OCR] Sending image to Neural Hub. Size: ${sizeInMB.toFixed(2)}MB`
      );

      setProgress(20);

      // Start a smooth progress animation while waiting
      const progressInterval = setInterval(() => {
        setProgress((prev) => {
          if (prev < 85) return prev + 5;
          return prev;
        });
      }, 800);

      try {
        const response = await fetch('/api/ocr', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ image: base64Image }),
        });

        clearInterval(progressInterval);
        setProgress(90);

        const data = await response.json();

        if (!response.ok) {
          // If server provides a detailed reason, show it, otherwise fallback to generic
          const errorMsg = data.error || 'Neural cluster is busy.';
          const detailMsg =
            data.details || 'Please try Standard Mode for local processing.';
          throw new Error(`${errorMsg} ${detailMsg}`);
        }

        setProgress(100);

        // Log success with provider info if available
        if (data.provider) {
          console.log(
            `[OCR] SUCCESS with ${data.provider} in ${data.processingTime}ms`
          );
        }

        return data.text;
      } finally {
        clearInterval(progressInterval);
      }
    } catch (e) {
      console.error('[OCR] API Fault:', e);
      throw e;
    }
  };

  const extractWithTesseract = async () => {
    // Preprocess image for better accuracy
    setProgress(5);
    const processedImage = await preprocessImage(previewUrl);
    setProgress(15);

    const result = await Tesseract.recognize(
      processedImage, // Use preprocessed image
      'eng',
      {
        logger: (m) => {
          if (m.status === 'recognizing text') {
            setProgress(15 + Math.round(m.progress * 85));
          }
        },
        // Optimal settings for maximum accuracy
        tessedit_ocr_engine_mode: 1, // LSTM neural network engine (most accurate)
        tessedit_pageseg_mode: 3, // Fully automatic page segmentation
        preserve_interword_spaces: 1, // Preserve spacing between words
        tessedit_char_whitelist: '', // Allow all characters
      }
    );
    return result.data.text.trim();
  };

  const handleExtractText = async () => {
    if (!selectedFile) return;

    setIsProcessing(true);
    setError('');
    setProgress(0);

    try {
      let text;

      if (useAI) {
        // AI Mode - Preprocess and compress first for better recognition/efficiency
        setProgress(10);
        const processedImage = await preprocessImage(previewUrl, true);
        setProgress(30);
        text = await extractWithAI(processedImage);
        setProgress(100);
      } else {
        // Standard Mode - Tesseract
        text = await extractWithTesseract();
      }

      if (!text || text.length === 0) {
        setError(
          'No text found in the image. Please try another image with clearer text.'
        );
      } else {
        setExtractedText(text);
        setError('');
        setProgress(100);
        toast.success('Intelligence Extracted Successfully');
        persistState({ extractedText: text });
      }
    } catch (err) {
      console.error('OCR Error:', err);
      setError(
        err.message ||
          'Failed to extract text. Please try again with a clearer image.'
      );
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCopy = () => {
    performAction(
      () => {
        navigator.clipboard.writeText(extractedText);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      },
      { type: 'copy', name: 'Image to Text' }
    );
  };

  const handleDownload = () => {
    performAction(
      () => {
        const blob = new Blob([extractedText], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'extracted-text.txt';
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      },
      { type: 'download', name: 'Image to Text' }
    );
  };

  const handleDragOver = (e) => {
    e.preventDefault();
    e.stopPropagation();
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();

    const file = e.dataTransfer.files?.[0];
    if (file) {
      const event = { target: { files: [file] } };
      handleFileSelect(event);
    }
  };

  // Handle clipboard paste (Ctrl+V)
  const handlePaste = useCallback(
    (e) => {
      const items = e.clipboardData?.items;
      if (!items) return;

      for (let i = 0; i < items.length; i++) {
        if (items[i].type.indexOf('image') !== -1) {
          const file = items[i].getAsFile();
          if (file) {
            const event = { target: { files: [file] } };
            handleFileSelect(event);
            break;
          }
        }
      }
    },
    [handleFileSelect]
  );

  // Listen for paste events globally
  useEffect(() => {
    document.addEventListener('paste', handlePaste);
    return () => document.removeEventListener('paste', handlePaste);
  }, [handlePaste]);

  return (
    <div className="max-w-6xl mx-auto space-y-8">
      {/* Header */}
      <motion.div
        className="text-center"
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
      >
        <h2 className="text-4xl font-black bg-gradient-to-r from-primary via-blue-500 to-cyan-500 bg-clip-text text-transparent mb-3">
          AI Image to Text Converter
        </h2>
        <p className="text-muted-foreground text-lg">
          Extract text from images using advanced AI or standard OCR
        </p>
      </motion.div>

      {/* AI Toggle */}
      <motion.div
        className="flex justify-center"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.1 }}
      >
        <div className="glass-panel p-2 rounded-full flex gap-2">
          <button
            onClick={() => setUseAI(false)}
            className={`px-6 py-2 rounded-full font-bold text-sm transition-all flex items-center gap-2 ${
              !useAI
                ? 'bg-gradient-to-r from-blue-500 to-cyan-500 text-white'
                : 'text-foreground/60 hover:text-foreground'
            }`}
          >
            <Zap className="w-4 h-4" />
            Standard Mode
          </button>
          <button
            onClick={() => setUseAI(true)}
            className={`px-6 py-2 rounded-full font-bold text-sm transition-all flex items-center gap-2 ${
              useAI
                ? 'bg-gradient-to-r from-purple-500 to-pink-500 text-white'
                : 'text-foreground/60 hover:text-foreground'
            }`}
          >
            <Sparkles className="w-4 h-4" />
            AI Mode (Best)
          </button>
        </div>
      </motion.div>

      <div className="grid lg:grid-cols-2 gap-8">
        {/* Upload Section */}
        <motion.div
          className="space-y-6"
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ delay: 0.2 }}
        >
          <div className="glass-panel p-8 rounded-3xl border border-border">
            <h3 className="text-2xl font-bold text-foreground mb-4 flex items-center gap-2">
              <Upload className="w-6 h-6" />
              Upload Image
            </h3>

            {/* Drag & Drop Area */}
            <div
              className="border-2 border-dashed border-border rounded-2xl p-8 text-center hover:border-primary transition-colors cursor-pointer relative overflow-hidden group"
              onDragOver={handleDragOver}
              onDrop={handleDrop}
              onClick={() => document.getElementById('fileInput')?.click()}
            >
              <motion.div className="absolute inset-0 bg-primary/5 opacity-0 group-hover:opacity-100 transition-opacity" />

              <div className="relative z-10">
                <div className="flex justify-center gap-4 mb-4">
