  };

  const reset = () => {
    if (activeFile?.preview) URL.revokeObjectURL(activeFile.preview);
    if (result?.url) URL.revokeObjectURL(result.url);
    setActiveFile(null);
    setResult(null);
    setProgress(0);
    setUseTargetSize(false);
  };

  // --- RENDER: EMPTY STATE ---
  if (!activeFile) {
