              </div>

              <div className="h-8 w-px bg-border shadow-[0_0_10px_rgba(0,0,0,0.1)]" />

              <div className="text-left">
                <p className="text-[8px] uppercase text-green-500/80 tracking-[0.2em] font-black mb-1">
                  {useTargetSize ? 'Target' : 'Est. Output'}
