                          ?.desc}
                  </span>
                </div>
              )}
            </ProgressButton>
          )}
        </div>
      </div>

      {/* History Panel */}
      <div className="w-full max-w-[1600px] mx-auto mt-8 px-4">
        <ToolHistoryPanel
          toolType="video_compressor"
          refreshTrigger={historyRefresh}
        />
      </div>
    </div>
  );
}

