'use client';

import { Button } from '@/components/ui/button';
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
} from '@/components/ui/sheet';
import { ScrollArea } from '@/components/ui/scroll-area';
import { useState, useEffect } from 'react';
import {
  Eye,
  Copy,
  X,
  Check,
  Code as CodeIcon,
  Layout,
  Sparkles,
} from 'lucide-react';

export function PreviewDrawer({
  open,
  onOpenChange,
  title,
  content: initialContent,
  onCopy,
  data,
  code: initialCode, // Add support for 'code' prop from HTMLCleaner
}) {
  const [copied, setCopied] = useState(false);
  const [copiedMap, setCopiedMap] = useState({});
  const [viewMode, setViewMode] = useState('visual'); // visual, code
  const [localContent, setLocalContent] = useState('');

  // Sync local content when initial content/code changes
  useEffect(() => {
    setLocalContent(initialCode || initialContent || '');
  }, [initialContent, initialCode, open]);

  const handleCopy = async () => {
    if (localContent) {
      await navigator.clipboard.writeText(localContent);
      setCopied(true);
      onCopy?.();
      setTimeout(() => setCopied(false), 2000);
    }
  };

  // Process HTML to add SEO attributes
  const processSEO = (html) => {
    if (!html || typeof html !== 'string') return html;
    let processed = html.replace(
      /\<a\s+(?:[^>]*?\s+)?href=(["'])(.*?)\1([^>]*)\>/gi,
      (match, p1, p2, p3) => {
        let cleanP3 = p3
          .replace(/\s+(target|rel)=["'][^"']*?["']/gi, '')
          .trim();
        const isInternalLink = p2.toLowerCase().includes('hazwoper-osha.com');
        let newTag = '<a href="' + p2 + '" target="_blank"';
        if (!isInternalLink) newTag += ' rel="noopener noreferrer"';
        if (cleanP3) newTag += ' ' + cleanP3;
        newTag += '>';
        return newTag;
      }
    );
    return processed.replace(/&nbsp;/g, ' ');
  };

  const copyText = async (text, key) => {
    await navigator.clipboard.writeText(processSEO(text));
    if (key) {
      setCopiedMap((prev) => ({ ...prev, [key]: true }));
      // Removed timeout to make the highlight permanent per user request
    }
  };

  const isFaqView =
    title?.toLowerCase().includes('faq') &&
    Array.isArray(data) &&
    data.length > 0;

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="right"
        className="!w-[90vw] p-0 border-l shadow-2xl flex flex-col h-full bg-background overflow-hidden"
        data-hide-default-close="true"
      >
        <SheetHeader className="flex flex-row items-center justify-between border-b border-border p-4 bg-muted/10 backdrop-blur-md sticky top-0 z-10">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              <div className="p-1.5 bg-primary/10 rounded-lg">
                <Eye className="h-5 w-5 text-primary" />
              </div>
              <SheetTitle className="text-xl font-black tracking-tight">
                {title} <span className="text-primary">Editor</span>
              </SheetTitle>
            </div>

            {!isFaqView && (
              <div className="flex bg-muted p-1 rounded-xl border border-border/50">
                <Button
                  variant={viewMode === 'visual' ? 'secondary' : 'ghost'}
                  size="sm"
                  className="rounded-lg gap-2 h-8 text-[11px] font-bold uppercase tracking-wider"
                  onClick={() => setViewMode('visual')}
                >
                  <Layout className="h-3.5 w-3.5" />
                  Visual
                </Button>
                <Button
                  variant={viewMode === 'code' ? 'secondary' : 'ghost'}
                  size="sm"
                  className="rounded-lg gap-2 h-8 text-[11px] font-bold uppercase tracking-wider"
                  onClick={() => setViewMode('code')}
                >
                  <CodeIcon className="h-3.5 w-3.5" />
                  Code
                </Button>
              </div>
            )}
          </div>

          <div className="flex items-center gap-3 pr-6">
            <Button
              variant="outline"
              size="sm"
              onClick={handleCopy}
              className={`gap-2 h-10 px-5 transition-all duration-500 rounded-xl font-bold border-2 ${copied ? 'border-green-500 text-green-500 bg-green-50/10' : 'hover:border-primary/50'}`}
            >
              {copied ? (
                <Check className="h-4 w-4" />
              ) : (
                <Copy className="h-4 w-4" />
              )}
              {copied ? 'Copied Content!' : 'Copy All'}
            </Button>
            <Button
              variant="secondary"
              size="icon"
              onClick={() => onOpenChange(false)}
              className="h-10 w-10 rounded-xl hover:bg-destructive hover:text-white transition-all duration-300 shadow-sm"
            >
              <X className="h-5 w-5" />
            </Button>
          </div>
        </SheetHeader>

        <ScrollArea className="flex-1">
          <div className="p-4 md:p-6 max-w-5xl mx-auto">
            {isFaqView ? (
              <div className="space-y-3">
                <div className="bg-gradient-to-br from-primary/10 via-background to-primary/5 border border-primary/20 p-4 rounded-2xl mb-4 shadow-sm relative overflow-hidden group">
                  <div className="absolute top-0 right-0 p-2 opacity-5 group-hover:opacity-10 transition-opacity">
                    <Sparkles className="h-12 w-12 text-primary rotate-12" />
                  </div>
                  <h4 className="font-bold text-primary text-sm mb-1 flex items-center gap-2 uppercase tracking-tight">
                    <Sparkles className="h-4 w-4" /> FAQ Workbench
                  </h4>
                  <p className="text-[11px] text-muted-foreground leading-snug max-w-2xl">
                    Refine and copy FAQs.{' '}
                    <span className="text-green-600 font-bold">Green</span>{' '}
                    indicates copied to clipboard.
                  </p>
                </div>

                <div className="space-y-3">
                  {data.map((faq, idx) => {
                    const qKey = `q-${idx}`;
                    const aKey = `a-${idx}`;
                    const isQCopied = copiedMap[qKey];
                    const isACopied = copiedMap[aKey];

                    return (
                      <div
                        key={idx}
                        className={`group border rounded-2xl overflow-hidden transition-all duration-500 p-4 relative ${
                          isQCopied || isACopied
                            ? 'bg-green-50/5 border-green-500/30'
                            : 'bg-card border-border/50 hover:border-primary/20'
                        }`}
                      >
                        {/* Status Indicator */}
                        {isQCopied && isACopied && (
                          <div className="absolute top-2 right-[50%] flex items-center gap-1 text-green-600 text-[9px] font-bold uppercase tracking-widest">
                            <Check className="h-2.5 w-2.5" /> Copied
                          </div>
                        )}

                        {/* Question Header */}
                        <div className="flex justify-between items-start gap-3 mb-3">
                          <div className="flex items-start gap-3 flex-1">
                            <span
                              className={`flex items-center justify-center w-7 h-7 rounded-lg font-bold text-xs shrink-0 shadow-sm ${
                                isQCopied
                                  ? 'bg-green-500 text-white'
                                  : 'bg-primary/10 text-primary'
                              }`}
                            >
                              {idx + 1}
                            </span>
                            <div className="flex flex-col gap-0.5 flex-1">
                              <span className="text-[9px] font-bold text-muted-foreground/60 uppercase tracking-widest">
                                Question
                              </span>
                              <div
                                contentEditable
                                suppressContentEditableWarning
                                className={`font-bold text-sm text-foreground outline-none focus:ring-1 focus:ring-primary/20 rounded-md p-1 transition-all min-h-[1.2em] w-full ${
                                  isQCopied ? 'bg-green-500/5' : ''
                                }`}
                                onBlur={(e) => {
                                  faq.question = e.target.innerText;
                                }}
                              >
                                {faq.question}
                              </div>
                            </div>
                          </div>
                          <Button
                            size="sm"
                            variant="outline"
                            className={`h-7 shrink-0 rounded-lg transition-all duration-300 gap-1.5 px-2 ${
                              isQCopied
                                ? 'bg-green-500 text-white border-green-500'
                                : 'bg-background hover:border-primary/50 opacity-0 group-hover:opacity-100'
                            }`}
                            onClick={() => copyText(faq.question, qKey)}
                          >
                            {isQCopied ? (
                              <Check className="h-3 w-3" />
                            ) : (
                              <Copy className="h-3 w-3" />
                            )}
                            <span className="text-[10px] font-bold uppercase">
                              {isQCopied ? 'Copied' : 'Copy'}
                            </span>
                          </Button>
                        </div>

                        {/* Condensed Divider */}
                        <div
                          className={`h-px transition-all duration-700 ${
                            isQCopied || isACopied
                              ? 'bg-green-100'
                              : 'bg-border/30'
                          } my-2`}
                        />

                        {/* Answer Body */}
                        <div className="flex justify-between items-start gap-3">
                          <div className="flex-1 pl-10">
                            <span className="text-[9px] font-bold text-muted-foreground/60 uppercase tracking-widest mb-1 block">
                              Answer
                            </span>
                            <div
                              contentEditable
                              suppressContentEditableWarning
                              className={`prose prose-xs dark:prose-invert max-w-none text-muted-foreground text-xs leading-normal outline-none focus:ring-1 focus:ring-primary/20 rounded-lg p-3 transition-all duration-500 ${
                                isACopied
                                  ? 'bg-green-500/5 text-green-900 dark:text-green-100'
                                  : 'bg-muted/20'
                              }`}
                              onBlur={(e) => {
                                faq.answer = e.target.innerHTML;
                              }}
                              dangerouslySetInnerHTML={{
                                __html: processSEO(faq.answer),
                              }}
                            />
                          </div>
                          <Button
                            size="sm"
                            variant="outline"
                            className={`h-7 shrink-0 rounded-lg transition-all duration-300 gap-1.5 px-2 mt-4 ${
                              isACopied
                                ? 'bg-green-500 text-white border-green-500'
                                : 'bg-background hover:border-primary/50 opacity-0 group-hover:opacity-100'
                            }`}
                            onClick={() => copyText(faq.answer, aKey)}
                          >
                            {isACopied ? (
                              <Check className="h-3 w-3" />
                            ) : (
                              <Copy className="h-3 w-3" />
                            )}
                            <span className="text-[10px] font-bold uppercase">
                              {isACopied ? 'Copied' : 'Copy'}
                            </span>
                          </Button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            ) : (
              <div className="flex flex-col gap-6 animate-in fade-in duration-500">
                {viewMode === 'visual' ? (
                  <div
                    contentEditable
                    suppressContentEditableWarning
                    className="preview-container prose prose-sm dark:prose-invert max-w-none rounded-lg border border-border p-6 bg-card outline-none focus:ring-1 focus:ring-primary/20"
                    onBlur={(e) => setLocalContent(e.target.innerHTML)}
                    dangerouslySetInnerHTML={{ __html: localContent }}
                  />
                ) : (
                  <div className="relative flex flex-col h-[75vh]">
                    <textarea
                      className="flex-1 w-full bg-muted/30 border rounded-md p-4 font-mono text-xs leading-relaxed resize-none focus:outline-none focus:ring-1 focus:ring-primary/20"
                      value={localContent}
                      onChange={(e) => setLocalContent(e.target.value)}
                      spellCheck="false"
                    />
                  </div>
                )}
              </div>
            )}
          </div>
        </ScrollArea>
      </SheetContent>
      <style jsx global>{`
        [contenteditable]:empty:before {
          content: attr(data-placeholder);
          color: #888;
          font-style: italic;
        }
        .preview-container table {
          width: 100% !important;
          border-collapse: separate;
          border-spacing: 0;
          margin: 2rem 0;
          border-radius: 16px;
          overflow: hidden;
          border: 1px solid rgba(128, 128, 128, 0.1);
        }
        .preview-container table th,
        .preview-container table td {
          border: 1px solid rgba(128, 128, 128, 0.1) !important;
          padding: 16px !important;
        }
        .preview-container table th {
          background: rgba(128, 128, 128, 0.05);
          font-weight: 900;
          text-transform: uppercase;
          font-size: 11px;
          letter-spacing: 0.05em;
        }
      `}</style>
    </Sheet>
  );
}

'use client';

import { useEffect, useRef, useState, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import {
  Save,
  Eye,
  Download,
  Undo,
  Redo,
  Bold,
  Italic,
  Underline,
  Link,
  List,
  ListOrdered,
  Image as ImageIcon,
  ChevronDown,
  X,
  Table,
  LayoutGrid,
  Columns,
  Palette,
  AlignLeft,
  AlignCenter,
  AlignRight,
  AlignJustify,
  ArrowUp,
  ArrowDown,
  MoveVertical,
  Check,
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { toast } from 'sonner';

export function RichTextEditor({ content, onSave, title = 'Editor' }) {
  const editorRef = useRef(null);
  const [isReady, setIsReady] = useState(false);
  const [history, setHistory] = useState([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const initialContentRef = useRef(content);
  const [showFloatingToolbar, setShowFloatingToolbar] = useState(false);
  const [floatingToolbarPosition, setFloatingToolbarPosition] = useState({
    top: 0,
    left: 0,
  });
  const toolbarRootRef = useRef(null);
  const saveTimeoutRef = useRef(null);

  // Blog settings state
  const [showImageTools, setShowImageTools] = useState(false);
  const [featuredImageUrl, setFeaturedImageUrl] = useState('');
  const [featuredImageAlt, setFeaturedImageAlt] = useState('');
  const [currentHeading, setCurrentHeading] = useState('p');
  const [activeTable, setActiveTable] = useState(null);
  const [showTableOptions, setShowTableOptions] = useState(false);
  const [showColorPalette, setShowColorPalette] = useState(false);

  const colors = [
    '#000000',
    '#ffffff',
    '#212529',
    '#f8f9fa',
    '#0d6efd',
    '#6610f2',
    '#6f42c1',
    '#d63384',
    '#dc3545',
    '#fd7e14',
    '#ffc107',
    '#198754',
    '#20c997',
    '#0dcaf0',
    '#adb5bd',
    '#dee2e6',
  ];

  // Initialize editor with content
  useEffect(() => {
    if (editorRef.current && content) {
      // Only set content if it's different from current content
      if (editorRef.current.innerHTML !== content) {
        editorRef.current.innerHTML = content;
        // Initialize history with first state in next tick to avoid cascading renders
        setTimeout(() => {
          if (editorRef.current) {
            setHistory([content]);
            setHistoryIndex(0);
            setIsReady(true);
          }
        }, 0);
      } else {
        setTimeout(() => setIsReady(true), 0);
      }
    }
  }, [content]);

  // Save current state to history
  const saveToHistory = useCallback(() => {
    if (!editorRef.current) return;

    const currentContent = editorRef.current.innerHTML;
    setHistory((prev) => {
      const newHistory = prev.slice(0, historyIndex + 1);
      // Don't save if content is identical to last state
      if (newHistory[newHistory.length - 1] !== currentContent) {
        newHistory.push(currentContent);
      }
      return newHistory.slice(-50); // Keep last 50 states
    });
    setHistoryIndex((prev) => Math.min(prev + 1, 49));
  }, [historyIndex]);

  // Handle input changes
  const handleInput = useCallback(() => {
    // Proper debounce for history saving
    if (saveTimeoutRef.current) {
      clearTimeout(saveTimeoutRef.current);
    }

    saveTimeoutRef.current = setTimeout(() => {
      saveToHistory();
    }, 500);
  }, [saveToHistory]);

  const handleUndo = () => {
    if (historyIndex > 0 && editorRef.current) {
      const newIndex = historyIndex - 1;
      editorRef.current.innerHTML = history[newIndex];
      setHistoryIndex(newIndex);
    }
  };

  const handleRedo = () => {
    if (historyIndex < history.length - 1 && editorRef.current) {
      const newIndex = historyIndex + 1;
      editorRef.current.innerHTML = history[newIndex];
      setHistoryIndex(newIndex);
    }
  };

  // Format commands
  const execCommand = (command, value = null) => {
    document.execCommand(command, false, value);
    editorRef.current?.focus();
    saveToHistory();
  };

  const handleBold = () => execCommand('bold');
  const handleItalic = () => execCommand('italic');
  const handleUnderline = () => execCommand('underline');
  const handleTextColor = (color) => execCommand('foreColor', color);

  // Handle text selection to show floating toolbar
  const handleTextSelection = useCallback(() => {
    const selection = window.getSelection();
    if (selection && selection.toString().trim().length > 0) {
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();

      // Detect current heading - walk up the DOM tree
      let element = range.commonAncestorContainer;
      if (element.nodeType === 3) {
        // Text node, get parent element
        element = element.parentElement;
      }

      // Find the heading or paragraph element
      let foundHeading = 'p';
      while (element && element !== editorRef.current) {
        const tag = element.tagName?.toLowerCase();
        if (tag === 'p') {
          foundHeading = 'p';
          break;
        } else if (tag && tag.match(/^h[1-6]$/)) {
          foundHeading = tag;
          break;
        }
        element = element.parentElement;
      }
      setCurrentHeading(foundHeading);

      // Calculate center position for toolbar
      const toolbarWidth = 200; // Approximate width
      const toolbarHeight = 280; // Approximate height

      // Center horizontally on screen
      let left = window.innerWidth / 2 - toolbarWidth / 2;

      // Position vertically - prefer right side of selection
      let top = rect.top + window.scrollY;

      // Ensure toolbar doesn't go off screen
      if (top < 80) top = 80; // Don't go above fixed header
      if (top + toolbarHeight > window.innerHeight + window.scrollY) {
        top = window.innerHeight + window.scrollY - toolbarHeight - 20;
      }

      setFloatingToolbarPosition({ top, left });
      setShowFloatingToolbar(true);
    } else {
      setShowFloatingToolbar(false);
    }

    // Check for active table
    let node = selection.anchorNode;
    if (node && node.nodeType === 3) node = node.parentElement;
    const table = node ? node.closest('table') : null;
    setActiveTable(table);
    if (!table) setShowTableOptions(false);
  }, [setFloatingToolbarPosition, setShowFloatingToolbar]);

  // Hide floating toolbar when clicking elsewhere
  useEffect(() => {
    const handleGlobalClick = (e) => {
      if (editorRef.current && !editorRef.current.contains(e.target)) {
        // Small delay to allow button clicks in floating toolbar
        setTimeout(() => {
          const selection = window.getSelection();
          if (!selection || selection.toString().trim().length === 0) {
            setShowFloatingToolbar(false);
          }
        }, 100);
      }
    };
    document.addEventListener('mousedown', handleGlobalClick);
    return () => document.removeEventListener('mousedown', handleGlobalClick);
  }, [editorRef, setShowFloatingToolbar]);

  const handleLink = () => {
    const url = prompt('Enter URL:');
    if (url) {
      execCommand('createLink', url);
    }
  };

  const handleInsertUnorderedList = () => execCommand('insertUnorderedList');
  const handleInsertOrderedList = () => execCommand('insertOrderedList');

  const handleInsertTable = () => {
    const rows = prompt('Number of rows:', '3') || 3;
    const cols = prompt('Number of columns:', '3') || 3;

    let tableHtml =
      '<table class="table table-bordered table-container" style="display: block; width: 100%; overflow-x: auto; -webkit-overflow-scrolling: touch; -ms-overflow-style: -ms-autohiding-scrollbar; max-width: 850px; white-space: nowrap;">';

    // Header row
    tableHtml += '<thead><tr class="bg-warning text-white">';
    for (let j = 0; j < cols; j++) {
      tableHtml += `<th>Header ${j + 1}</th>`;
    }
    tableHtml += '</tr></thead><tbody>';

    // Data rows
    for (let i = 0; i < rows; i++) {
      tableHtml += '<tr>';
      for (let j = 0; j < cols; j++) {
        tableHtml += `<td>Data ${i + 1}-${j + 1}</td>`;
      }
      tableHtml += '</tr>';
    }

    tableHtml += '</tbody></table><p><br></p>';

    // Insert at cursor
    execCommand('insertHTML', tableHtml);
  };

  const applyTableClass = (className) => {
    const selection = window.getSelection();
    if (!selection.rangeCount) return;

    let element = selection.anchorNode;
    if (element.nodeType === 3) element = element.parentElement;

    const table = element.closest('table');
    if (table) {
      if (className === 'table-stripe') {
        table.classList.toggle('table-stripe');
      } else if (className === 'table-warning') {
        table.classList.toggle('table-warning');
      }
      saveToHistory();
    } else {
      toast.error('Please click inside a table to apply this style.');
    }
  };

  const toggleTopHeader = () => {
    const selection = window.getSelection();
    if (!selection.rangeCount) return;
    let element = selection.anchorNode;
    if (element.nodeType === 3) element = element.parentElement;
    const table = element.closest('table');
    if (table) {
      const firstRow = table.querySelector('tr');
      if (firstRow) {
        firstRow.classList.toggle('bg-warning');
        firstRow.classList.toggle('text-white');
      }
      saveToHistory();
    }
  };

  const toggleLeftHeader = () => {
    const selection = window.getSelection();
    if (!selection.rangeCount) return;
    let element = selection.anchorNode;
    if (element.nodeType === 3) element = element.parentElement;
    const table = element.closest('table');
    if (table) {
      const rows = table.querySelectorAll('tr');
      rows.forEach((row) => {
        const firstCell = row.querySelector('td, th');
        if (firstCell) {
          firstCell.classList.toggle('bg-warning');
        }
      });
      saveToHistory();
    }
  };

  const handleAlignment = (alignment) => {
    execCommand(
      `justify${alignment.charAt(0).toUpperCase() + alignment.slice(1)}`
    );
  };

  const setTableCellAlignment = (axis, value) => {
    const selection = window.getSelection();
    if (!selection.rangeCount) return;
    let node = selection.anchorNode;
    if (node.nodeType === 3) node = node.parentElement;
    const cell = node.closest('td, th');
    if (cell) {
      if (axis === 'x') {
        cell.style.textAlign = value;
      } else {
        cell.style.verticalAlign = value;
      }
      saveToHistory();
    }
  };

  // Convert HTML to have proper Bootstrap classes when saving
  const processHTMLForSave = (html) => {
    if (!html) return '';

    const tempDiv = document.createElement('div');
    tempDiv.innerHTML = html;

    // Process H1 tags - add text-center fs-1 class
    tempDiv.querySelectorAll('h1').forEach((h1) => {
      h1.className = 'text-center fs-1';
    });

    // Process H2 tags - add fs-2 class
    tempDiv.querySelectorAll('h2').forEach((h2) => {
      h2.className = 'fs-2';
    });

    // Process H3 tags - add fs-3 class
    tempDiv.querySelectorAll('h3').forEach((h3) => {
      h3.className = 'fs-3';
    });

    // Process H4 tags - add fs-4 class
    tempDiv.querySelectorAll('h4').forEach((h4) => {
      h4.className = 'fs-4';
    });

    // Process H5 tags - add fs-5 class
    tempDiv.querySelectorAll('h5').forEach((h5) => {
      h5.className = 'fs-5';
    });

    // Process H6 tags - add fs-6 class
    tempDiv.querySelectorAll('h6').forEach((h6) => {
      h6.className = 'fs-6';
    });

    // Process Tables - add Bootstrap 'table' class and ensure container
    tempDiv.querySelectorAll('table').forEach((table) => {
      table.classList.add('table');
      table.classList.add('table-container');
      if (!table.classList.contains('table-bordered')) {
        table.classList.add('table-bordered');
      }
      table.setAttribute(
        'style',
        'display: block; width: 100%; overflow-x: auto; -webkit-overflow-scrolling: touch; -ms-overflow-style: -ms-autohiding-scrollbar; max-width: 850px; white-space: nowrap;'
      );

      // Unwrap if inside a div.table-container
      const parent = table.parentElement;
      if (parent && parent.className === 'table-container') {
        parent.replaceWith(table);
      }
    });

    // Remove <strong> and <b> tags from inside ALL headings (h1-h6)
    // Headings don't need bold tags - they are already bold by default
    tempDiv.querySelectorAll('h1, h2, h3, h4, h5, h6').forEach((heading) => {
      // Find all strong and b tags inside this heading
      heading.querySelectorAll('strong, b').forEach((boldTag) => {
        // Replace the bold tag with just its text content
        const textNode = document.createTextNode(boldTag.textContent);
        boldTag.parentNode.replaceChild(textNode, boldTag);
      });
    });

    // Convert <b> to <strong> for SEO
    tempDiv.querySelectorAll('b').forEach((b) => {
      const strong = document.createElement('strong');
      strong.innerHTML = b.innerHTML;
      b.parentNode.replaceChild(strong, b);
    });

    // Convert <i> to <em> for SEO
    tempDiv.querySelectorAll('i').forEach((i) => {
      const em = document.createElement('em');
      em.innerHTML = i.innerHTML;
      i.parentNode.replaceChild(em, i);
    });

    // Add <hr> after first H1 if not already present
    const firstH1 = tempDiv.querySelector('h1');
    if (firstH1 && firstH1.nextElementSibling?.tagName !== 'HR') {
      const hr = document.createElement('hr');
      firstH1.after(hr);
    }

    // Ensure tables have responsive wrapper if missing
    tempDiv.querySelectorAll('table').forEach((table) => {
      if (!table.parentElement.classList.contains('table-container')) {
        const wrapper = document.createElement('div');
        wrapper.className = 'table-container';
        wrapper.setAttribute(
          'style',
          'display: block;width: 100%;overflow-x: auto;-webkit-overflow-scrolling: touch;-ms-overflow-style: -ms-autohiding-scrollbar;max-width: 850px;white-space: nowrap;'
        );
        table.parentNode.insertBefore(wrapper, table);
        wrapper.appendChild(table);
      }
    });

    let finalHTML = tempDiv.innerHTML;

    // Don't add fancy line here - it will be added when generating blog code
    // This prevents duplicate fancy lines on multiple saves

    return finalHTML;
  };

  // Save editor content and pass to parent component
  const handleSave = () => {
    if (editorRef.current) {
      const rawHTML = editorRef.current.innerHTML;
      const processedHTML = processHTMLForSave(rawHTML);

      // Just save the content and image data - no fancy line, no duplicates
      if (onSave) {
        onSave(processedHTML, {
          featuredImageUrl: featuredImageUrl,
          featuredImageAlt: featuredImageAlt,
        });
      }

      toast.success('Professional Assets Saved');
    }
  };

  const handlePreview = () => {
    if (editorRef.current) {
      const rawHTML = editorRef.current.innerHTML;
      const processedHTML = processHTMLForSave(rawHTML);

      // Open preview in new window
      const previewWindow = window.open('', '_blank');
      previewWindow.document.write(`
