						}

						/* Bold */
						strong, b { 
							font-weight: 800;
							color: #111827;
							letter-spacing: -0.01em;
						}

						/* Italic */
						em, i {
							font-style: italic;
							color: #4b5563;
						}

						/* Underline */
					u {
						text-decoration: underline;
						text-decoration-color: #06b6d4;
						text-decoration-thickness: 2px;
						text-underline-offset: 3px;
					}

					/* Default margins */
					h1, h2, h3, h4, h5, h6 {
						margin-top: 1.5rem;
						margin-bottom: 1rem;
					}

					p {
						margin-top: 1rem;
						margin-bottom: 1rem;
					}

					ul, ol {
						margin-top: 1rem;
						margin-bottom: 1rem;
						padding-left: 2rem;
					}

					li {
						margin-bottom: 0.5rem;
					}

					/* Links */
					a { 
						color: #8b5cf6;
						text-decoration: none;
						border-bottom: 2px solid rgba(139, 92, 246, 0.35);
						transition: all 0.25s ease;
						font-weight: 600;
						padding: 0 2px;
					}

					a:hover { 
						color: #7c3aed;
						border-bottom-color: #7c3aed;
						background: rgba(139, 92, 246, 0.08);
						border-radius: 4px;
						padding: 2px 6px;
					}

					/* Table Styles */
					.table-container {
						margin: 2rem 0;
						border-radius: 8px;
						overflow: hidden;
						box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
					}
					table {
					  width: 100%;
					  border-collapse: collapse;
					  background: white;
					}
					table tr p { margin-bottom: 0px; }
					th, td {
					  padding: 12px 15px;
					  border: 1px solid #e5e7eb;
					  text-align: left;
					}
					.bg-warning {
					  background-color: #ffcd05 !important;
					  color: #1a1a1a !important;
					}
					.table-stripe tr:nth-child(even) {
					  background-color: #fff9e6; /* Light Yellow Stripe */
					}
					.table-warning tr:nth-child(even) {
					  background-color: #fffde6; /* Very light yellow stripe */
					}
					thead th {
					  background-color: #f3f4f6;
					  font-weight: 700;
					}
					</style>
				</head>
				<body>
					${processedHTML}
				</body>
				</html>
			`);
      previewWindow.document.close();
    }
  };

  const handleDownload = () => {
    if (editorRef.current) {
      const rawHTML = editorRef.current.innerHTML;
      const processedHTML = processHTMLForSave(rawHTML);

      const blob = new Blob([processedHTML], { type: 'text/html' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${title.replace(/\s+/g, '_').toLowerCase()}.html`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    }
  };

  return (
    <div
      className="bg-background dark:bg-slate-950 flex flex-col relative h-full"
      ref={toolbarRootRef}
    >
      {/* Fixed Toolbar at Top */}
      <div className="fixed left-0 right-0 z-[200] flex items-center justify-between gap-1 p-2 border-b bg-background/95 dark:bg-slate-900/95 shadow-md backdrop-blur-md px-4 py-1.5">
        <div className="flex items-center gap-1">
          <Button
            variant="outline"
            size="sm"
            onClick={handleUndo}
            disabled={!isReady || historyIndex <= 0}
            className="h-7 w-7 p-0"
            title="Undo"
          >
            <Undo className="h-3 w-3" />
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={handleRedo}
            disabled={!isReady || historyIndex >= history.length - 1}
            className="h-7 w-7 p-0"
            title="Redo"
          >
            <Redo className="h-3 w-3" />
          </Button>
          <div className="w-px h-6 bg-border mx-1" />
          <Button
            variant="outline"
            size="sm"
            onClick={handleBold}
            disabled={!isReady}
            className="h-7 w-7 p-0 font-bold"
            title="Bold (Ctrl+B)"
          >
            <Bold className="h-3 w-3" />
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={handleItalic}
            disabled={!isReady}
            className="h-7 w-7 p-0 italic"
            title="Italic (Ctrl+I)"
          >
            <Italic className="h-3 w-3" />
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={handleUnderline}
            disabled={!isReady}
            className="h-7 w-7 p-0 underline"
            title="Underline (Ctrl+U)"
          >
            <Underline className="h-3 w-3" />
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={handleLink}
            disabled={!isReady}
            className="h-7 w-7 p-0"
            title="Insert Link"
          >
            <Link className="h-3 w-3" />
          </Button>
          <div className="w-px h-6 bg-border mx-1" />
          <Button
            variant="outline"
            size="sm"
            onClick={handleInsertUnorderedList}
            disabled={!isReady}
            className="h-7 w-7 p-0"
            title="Bullet List"
          >
            <List className="h-3 w-3" />
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={handleInsertOrderedList}
            disabled={!isReady}
            className="h-7 w-7 p-0"
            title="Numbered List"
          >
            <ListOrdered className="h-3 w-3" />
          </Button>
          <div className="w-px h-6 bg-border mx-1" />

          {/* Professional Color Palette */}
          <div className="relative">
            <Button
              variant="outline"
              size="sm"
              onClick={() => setShowColorPalette(!showColorPalette)}
              disabled={!isReady}
              className="h-7 w-7 p-0 flex flex-col items-center justify-center"
              title="Text Color"
            >
              <Palette className="h-3.5 w-3.5" />
              <div className="w-full h-1 mt-0.5 bg-black rounded-full" />
            </Button>

            <AnimatePresence>
              {showColorPalette && (
                <motion.div
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: 10 }}
                  className="absolute top-full left-0 mt-2 bg-white dark:bg-slate-900 border rounded-lg shadow-xl p-3 z-[300] w-48"
                >
                  <div className="grid grid-cols-6 gap-2">
                    {colors.map((color) => (
                      <button
                        key={color}
                        onClick={() => {
                          handleTextColor(color);
                          setShowColorPalette(false);
                        }}
                        className="w-5 h-5 rounded-sm border border-black/10 transition-transform hover:scale-110 shadow-sm"
                        style={{ backgroundColor: color }}
                        title={color}
                      />
                    ))}
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          <div className="w-px h-6 bg-border mx-1" />

          {/* Alignment Tools */}
          <Button
            variant="outline"
            size="sm"
            onClick={() => handleAlignment('left')}
            className="h-7 w-7 p-0"
            title="Align Left"
          >
            <AlignLeft className="h-3 w-3" />
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={() => handleAlignment('center')}
            className="h-7 w-7 p-0"
            title="Align Center"
          >
            <AlignCenter className="h-3 w-3" />
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={() => handleAlignment('right')}
            className="h-7 w-7 p-0"
            title="Align Right"
          >
            <AlignRight className="h-3 w-3" />
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={() => handleAlignment('full')}
            className="h-7 w-7 p-0"
            title="Justify"
          >
            <AlignJustify className="h-3 w-3" />
          </Button>

          <div className="w-px h-6 bg-border mx-1" />

          {/* Heading selector */}
          <select
            value={currentHeading}
            onChange={(e) => {
              const tag = e.target.value;
              if (tag === 'p') {
                document.execCommand('formatBlock', false, 'P');
              } else {
                document.execCommand('formatBlock', false, tag.toUpperCase());
              }
              setCurrentHeading(tag);
            }}
            disabled={!isReady}
            className="h-7 ml-1 text-[11px] px-1 border rounded bg-transparent"
          >
            <option value="p">P</option>
            <option value="h1">H1</option>
            <option value="h2">H2</option>
            <option value="h3">H3</option>
            <option value="h4">H4</option>
            <option value="h5">H5</option>
            <option value="h6">H6</option>
          </select>
          <Button
            variant={showImageTools ? 'secondary' : 'ghost'}
            size="sm"
            onClick={() => setShowImageTools(!showImageTools)}
            className={`h-7 w-7 p-0 ml-1 ${showImageTools ? 'bg-purple-500/10 text-purple-600' : ''}`}
            title="Image Settings"
          >
            <ImageIcon className="h-3.5 w-3.5" />
          </Button>

          {/* Refined Table Logic */}
          <div className="relative flex items-center gap-1 ml-1 pl-1 border-l">
            <Button
              variant={activeTable ? 'default' : 'outline'}
              size="sm"
              onClick={() =>
                activeTable
                  ? setShowTableOptions(!showTableOptions)
                  : handleInsertTable()
              }
              disabled={!isReady}
              className={`h-7 w-7 p-0 ${activeTable ? 'bg-indigo-600 text-white' : ''}`}
              title={activeTable ? 'Table Management' : 'Insert Table'}
            >
              <Table className="h-3.5 w-3.5" />
            </Button>

            <AnimatePresence>
              {(showTableOptions || activeTable) && (
                <motion.div
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -10 }}
                  className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 p-0.5 rounded-md ml-1"
                >
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => applyTableClass('table-stripe')}
                    className="h-6 px-2 text-[9px] font-bold hover:bg-yellow-100"
                    title="Stripe"
                  >
                    STRIPE
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => applyTableClass('table-warning')}
                    className="h-6 px-2 text-[9px] font-bold hover:bg-orange-100"
                    title="Warning"
                  >
                    WARN
                  </Button>
                  <div className="w-px h-4 bg-slate-300 mx-0.5" />
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={toggleTopHeader}
                    className="h-6 w-6 p-0 hover:bg-blue-100"
                    title="Top Heading Warning"
                  >
                    <LayoutGrid className="h-3 w-3" />
                  </Button>
                  <Button
                    variant="ghost"
